package main

import (
	"io/ioutil"
	"net/http"
)

func webhookProxy(w http.ResponseWriter, r *http.Request) {
	if r.Method != "POST" {
		http.Error(w, "Only POST requests are allowed", http.StatusMethodNotAllowed)
		return
	}

	// Read the URL from request body
	body, err := ioutil.ReadAll(r.Body)
	if err != nil {
		http.Error(w, "Error reading request body", http.StatusInternalServerError)
		return
	}
	defer r.Body.Close()

	urlToFetch := string(body)

	// Fetch content from the provided URL
	resp, err := http.Get(urlToFetch)
	if err != nil {
		http.Error(w, "Error fetching content from the provided URL", http.StatusInternalServerError)
		return
	}
	defer resp.Body.Close()

	// Read response body
	responseBody, err := ioutil.ReadAll(resp.Body)
	if err != nil {
		http.Error(w, "Error reading response body", http.StatusInternalServerError)
		return
	}

	// Forward the response to the client
	w.WriteHeader(resp.StatusCode)
	_, err = w.Write(responseBody)
	if err != nil {
		http.Error(w, "Error writing response body", http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/proxy", webhookProxy)
	err := http.ListenAndServe(":8080", nil)
	if err != nil {
		panic(err)
	}
}